/**
 * @param {number} n
 * @param {number} pos
 * @param {number} k
 * @return {number}
 */
function solve(n, pos, k) {
    const MOD = 1000000007n;

    // Number of people to the left of pos (indices 0 to pos-1)
    const leftCount = pos;
    // Number of people to the right of pos (indices pos+1 to n-1)
    const rightCount = n - 1 - pos;

    // The person at 'pos' can choose 'L' or 'R', contributing a factor of 2 to the final answer.
    // This choice does not affect the visibility count k.

    // We need to choose 'i' people from the left side such that they choose 'L'
    // and 'leftCount - i' people from the left side such that they choose 'R'.
    // A person i < pos is visible if and only if they choose 'L'.
    // The number of visible people from the left is the number of people in [0, pos-1] who choose 'L'.
    // Let x be the number of people from the left (0 to pos-1) who choose 'L'.
    // There are 'leftCount' people on the left. We choose 'x' of them to be 'L'.
    // Number of ways to choose x from leftCount: C(leftCount, x)

    // Similarly, for people to the right (pos+1 to n-1), they are visible if and only if they choose 'R'.
    // Let y be the number of people from the right (pos+1 to n-1) who choose 'R'.
    // There are 'rightCount' people on the right. We choose 'y' of them to be 'R'.
    // Number of ways to choose y from rightCount: C(rightCount, y)

    // We need x + y = k.

    // Precompute factorials and inverse factorials for combinations (nCr)
    const MAX = n;
    const fact = new Array(MAX + 1);
    const invFact = new Array(MAX + 1);

    fact[0] = 1n;
    for (let i = 1; i <= MAX; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }

    // Modular exponentiation (a^b % m)
    function power(base, exp) {
        let res = 1n;
        base %= MOD;
        while (exp > 0n) {
            if (exp % 2n === 1n) res = (res * base) % MOD;
            base = (base * base) % MOD;
            exp /= 2n;
        }
        return res;
    }

    // Modular inverse (a^-1 % m) using Fermat's Little Theorem
    function modInverse(n) {
        return power(n, MOD - 2n);
    }

    invFact[MAX] = modInverse(fact[MAX]);
    for (let i = MAX - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * BigInt(i + 1)) % MOD;
    }

    // Combination function C(n, r) % MOD
    function combinations(nn, rr) {
        if (rr < 0 || rr > nn) return 0n;
        if (rr === 0 || rr === nn) return 1n;
        if (rr > nn / 2) rr = nn - rr;

        // C(nn, rr) = nn! / (rr! * (nn-rr)!)
        let res = fact[nn];
        res = (res * invFact[rr]) % MOD;
        res = (res * invFact[nn - rr]) % MOD;
        return res;
    }

    let totalWays = 0n;

    // Iterate over all possible number of visible people from the left side (x)
    // x must satisfy:
    // 1. 0 <= x <= leftCount
    // 2. 0 <= k - x <= rightCount  =>  k - rightCount <= x <= k

    const startX = Math.max(0, k - rightCount);
    const endX = Math.min(leftCount, k);

    for (let x = startX; x <= endX; x++) {
        // If x people on the left see, then y = k - x people must see from the right.
        const y = k - x;

        // Ways to get x visible from left: C(leftCount, x)
        const waysLeft = combinations(leftCount, x);

        // Ways to get y visible from right: C(rightCount, y)
        const waysRight = combinations(rightCount, y);

        // Total ways for this split (x, y)
        const waysForXY = (waysLeft * waysRight) % MOD;

        totalWays = (totalWays + waysForXY) % MOD;
    }

    // The person at 'pos' can choose 'L' or 'R' (2 ways), independent of the visibility count.
    const finalAnswer = (totalWays * 2n) % MOD;

    return Number(finalAnswer);
}

